"use client";

import { memo, useMemo } from "react";
import {
  DEFAULT_MEDIA_CAROUSEL_LABELS,
  type MediaCarousel01Handle,
  type MediaCarousel01Labels,
  type MediaCarousel01Props,
} from "./types";
import { CarouselTrack } from "./parts/carousel-track";
import { SingleItem } from "./parts/single-item";

interface MediaCarousel01InnerProps extends MediaCarousel01Props {
  ref?: React.Ref<MediaCarousel01Handle>;
}

function MediaCarousel01Inner({
  items,
  variant,
  peekRatio = 0.075,
  aspect = "square",
  loop,
  showIndicators = true,
  showNavButtons = true,
  rtl = false,
  renderItem,
  onSlideChange,
  onDoubleTap,
  labels: labelsProp,
  className,
  slideClassName,
  ref,
}: MediaCarousel01InnerProps) {
  const labels = useMemo<Required<MediaCarousel01Labels>>(
    () => ({ ...DEFAULT_MEDIA_CAROUSEL_LABELS, ...labelsProp }),
    [labelsProp],
  );

  if (items.length === 0) return null;

  if (items.length === 1) {
    return (
      <SingleItem
        item={items[0]}
        renderItem={renderItem}
        onDoubleTap={onDoubleTap}
        labels={labels}
        className={className}
        slideClassName={slideClassName}
        variant={variant}
        aspect={aspect}
      />
    );
  }

  return (
    <CarouselTrack
      ref={ref}
      items={items}
      variant={variant}
      peekRatio={peekRatio}
      aspect={aspect}
      loop={loop ?? true}
      showIndicators={showIndicators}
      showNavButtons={showNavButtons}
      rtl={rtl}
      renderItem={renderItem}
      onSlideChange={onSlideChange}
      onDoubleTap={onDoubleTap}
      labels={labels}
      className={className}
      slideClassName={slideClassName}
    />
  );
}

const MediaCarousel01 = memo(MediaCarousel01Inner);
MediaCarousel01.displayName = "MediaCarousel01";

export { MediaCarousel01 };
export default MediaCarousel01;

export { default as MediaCarousel01 } from "./media-carousel-01";

export type {
  MediaCarousel01Props,
  MediaCarousel01Handle,
  MediaCarousel01Labels,
  MediaCarousel01Variant,
  MediaItem,
  RenderItemContext,
  LinearAspect,
} from "./types";

export { DEFAULT_MEDIA_CAROUSEL_LABELS } from "./types";

import type { ReactNode } from "react";

export type MediaCarousel01Variant = "gallery" | "linear";

export type LinearAspect = "square" | "video" | "portrait" | "auto";

/** Discriminated union — strict shape. */
export type MediaItem =
  | {
      id: string;
      type: "image";
      url: string;
      alt?: string;
    }
  | {
      id: string;
      type: "video";
      url: string;
      alt?: string;
      poster?: string;
    };

export interface RenderItemContext {
  /** True when this slide is the currently centered/snapped slide. */
  isActive: boolean;
  /** Index of this slide in the items array. */
  index: number;
}

export interface MediaCarousel01Labels {
  /** Default: "Media carousel". aria-label on the carousel region. */
  carouselLabel?: string;
  /** Default: "Previous slide". aria-label on the prev nav button. */
  previousSlide?: string;
  /** Default: "Next slide". aria-label on the next nav button. */
  nextSlide?: string;
  /** Default: "Go to slide". aria-label prefix on indicator dots; full label = "{prefix} {n}". */
  goToSlide?: string;
  /** Default: "Slide {index} of {total}". {index} and {total} are placeholders. */
  slideAriaLabel?: string;
}

export interface MediaCarousel01Props {
  /** Items to render. Required. */
  items: MediaItem[];
  /** Variant — `gallery` (peek-scale) or `linear` (snap). Required. */
  variant: MediaCarousel01Variant;

  // ─── Per-variant config ──────────────────────────────────────────
  /** Gallery only: peek ratio per side (e.g., 0.075 = 7.5%). Default: 0.075. */
  peekRatio?: number;
  /** Linear only: aspect ratio. Default: "square". */
  aspect?: LinearAspect;

  // ─── Carousel behavior ───────────────────────────────────────────
  /** Loop slides. Default: items.length > 1. */
  loop?: boolean;
  /** Show indicator dots. Default: true. Always hidden when items.length <= 1. */
  showIndicators?: boolean;
  /** Show side nav buttons. Default: true. Always hidden when items.length <= 1. */
  showNavButtons?: boolean;
  /** RTL direction. Default: false. */
  rtl?: boolean;

  // ─── Customization ───────────────────────────────────────────────
  /** Custom per-slide renderer — bypasses both built-in handlers. */
  renderItem?: (item: MediaItem, ctx: RenderItemContext) => ReactNode;

  // ─── Callbacks ───────────────────────────────────────────────────
  /** Fires on Embla `select` event (post-snap; once per slide commit). */
  onSlideChange?: (index: number) => void;
  /** Fires on double-tap of any slide. Unified for image + video items. */
  onDoubleTap?: (item: MediaItem, index: number) => void;

  // ─── i18n ────────────────────────────────────────────────────────
  /** Localized labels. Defaults are English. */
  labels?: MediaCarousel01Labels;

  // ─── Style overrides ─────────────────────────────────────────────
  /** Override classes for the wrapping <div>. */
  className?: string;
  /** Override classes per slide wrapper. */
  slideClassName?: string;
}

export interface MediaCarousel01Handle {
  /** Scroll to a specific slide (0-indexed). */
  scrollTo: (index: number) => void;
  /** Scroll to previous slide. */
  scrollPrev: () => void;
  /** Scroll to next slide. */
  scrollNext: () => void;
  /** Get the currently active slide index. */
  getCurrentIndex: () => number;
}

/** Default English labels — exported for consumer composition. */
export const DEFAULT_MEDIA_CAROUSEL_LABELS: Required<MediaCarousel01Labels> = {
  carouselLabel: "Media carousel",
  previousSlide: "Previous slide",
  nextSlide: "Next slide",
  goToSlide: "Go to slide",
  slideAriaLabel: "Slide {index} of {total}",
};

"use client";

import type { ReactNode } from "react";
import { cn } from "@/lib/utils";
import { useDoubleTap } from "@/registry/components/media/video-player-01";
import { SlideRenderer } from "./slide-renderer";
import type {
  LinearAspect,
  MediaCarousel01Labels,
  MediaCarousel01Variant,
  MediaItem,
  RenderItemContext,
} from "../types";

interface SingleItemProps {
  item: MediaItem;
  renderItem?: (item: MediaItem, ctx: RenderItemContext) => ReactNode;
  onDoubleTap?: (item: MediaItem, index: number) => void;
  labels: Required<MediaCarousel01Labels>;
  variant: MediaCarousel01Variant;
  aspect: LinearAspect;
  className?: string;
  slideClassName?: string;
}

/**
 * Single-item shortcut — bypass Embla entirely.
 *
 * Lives in its own component so `useDoubleTap` is called unconditionally
 * within it (own hook count, distinct from `<CarouselTrack>`). Switching
 * between single-item and carousel modes happens via component swap at
 * the root, not conditional hook calls.
 */
export function SingleItem({
  item,
  renderItem,
  onDoubleTap,
  labels,
  variant,
  aspect,
  className,
  slideClassName,
}: SingleItemProps) {
  const handleDoubleTap = useDoubleTap(
    onDoubleTap ? () => onDoubleTap(item, 0) : undefined,
  );

  return (
    <div
      className={cn(
        "relative aspect-square overflow-hidden bg-muted",
        className,
      )}
      onClick={handleDoubleTap}
      aria-label={labels.carouselLabel}
    >
      <SlideRenderer
        item={item}
        ctx={{ isActive: true, index: 0 }}
        renderItem={renderItem}
        // Already handled at wrapper level; don't double-fire.
        onDoubleTap={undefined}
        variant={variant}
        aspect={aspect}
        slideClassName={slideClassName}
        isSingleItem
      />
    </div>
  );
}

"use client";

import type { KeyboardEvent as ReactKeyboardEvent, ReactNode, Ref } from "react";
import {
  useCallback,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
} from "react";
import { cn } from "@/lib/utils";
import { useDoubleTap } from "@/registry/components/media/video-player-01";
import { useEmblaWithState } from "../hooks/use-embla-with-state";
import type {
  LinearAspect,
  MediaCarousel01Handle,
  MediaCarousel01Labels,
  MediaCarousel01Variant,
  MediaItem,
  RenderItemContext,
} from "../types";
import { IndicatorDots } from "./indicator-dots";
import { NavButtons } from "./nav-buttons";
import { SlideRenderer } from "./slide-renderer";

interface CarouselTrackProps {
  items: MediaItem[];
  variant: MediaCarousel01Variant;
  peekRatio: number;
  aspect: LinearAspect;
  loop: boolean;
  showIndicators: boolean;
  showNavButtons: boolean;
  rtl: boolean;
  renderItem?: (item: MediaItem, ctx: RenderItemContext) => ReactNode;
  onSlideChange?: (index: number) => void;
  onDoubleTap?: (item: MediaItem, index: number) => void;
  labels: Required<MediaCarousel01Labels>;
  className?: string;
  slideClassName?: string;
  ref?: Ref<MediaCarousel01Handle>;
}

interface SlideProps {
  item: MediaItem;
  index: number;
  total: number;
  isActive: boolean;
  isFirst: boolean;
  isLast: boolean;
  loop: boolean;
  variant: MediaCarousel01Variant;
  peekRatio: number;
  aspect: LinearAspect;
  renderItem?: (item: MediaItem, ctx: RenderItemContext) => ReactNode;
  onDoubleTap?: (item: MediaItem, index: number) => void;
  labels: Required<MediaCarousel01Labels>;
  slideClassName?: string;
}

function Slide({
  item,
  index,
  total,
  isActive,
  isFirst,
  isLast,
  loop,
  variant,
  peekRatio,
  aspect,
  renderItem,
  onDoubleTap,
  labels,
  slideClassName,
}: SlideProps) {
  // Image items: attach double-tap on the slide wrapper. Video items: handled
  // inside SlideRenderer via VideoPlayer01's onDoubleTap. Both fire the same
  // unified onDoubleTap callback.
  const imageDoubleTap = useDoubleTap(
    item.type === "image" && onDoubleTap
      ? () => onDoubleTap(item, index)
      : undefined,
  );

  const slideAriaLabel = labels.slideAriaLabel
    .replace("{index}", String(index + 1))
    .replace("{total}", String(total));

  // Match kasder layout exactly: outer slide gets flex-basis + small horizontal
  // gutter via `mx-1`; first/last get larger edge padding so the peek shows on
  // both ends (only meaningful when loop=false; under loop the clones eat it).
  // Inner wrapper is the visual frame — scale + opacity for inactive neighbors,
  // matching the kasder peek-scale aesthetic.
  if (variant === "gallery") {
    // Edge peek padding only matters when NOT looping. Under loop, Embla clones
    // the slides so first/last in DOM != first/last in source — applying edge
    // padding to the source first/last would create asymmetric slide widths
    // that break Embla's loop math.
    const edgePeekPercent = peekRatio * 100;
    return (
      <div
        role="group"
        aria-roledescription="slide"
        aria-label={slideAriaLabel}
        inert={!isActive}
        className={cn("min-w-0 mx-1 flex-[0_0_85%]")}
        style={{
          marginLeft: !loop && isFirst ? `${edgePeekPercent}%` : undefined,
          marginRight: !loop && isLast ? `${edgePeekPercent}%` : undefined,
        }}
        onClick={item.type === "image" ? imageDoubleTap : undefined}
      >
        <div
          className={cn(
            "overflow-hidden rounded-lg transition-all duration-300",
            isActive
              ? "scale-100 opacity-100"
              : "scale-95 opacity-60 blur-[1px]",
          )}
        >
          <SlideRenderer
            item={item}
            ctx={{ isActive, index }}
            renderItem={renderItem}
            onDoubleTap={onDoubleTap}
            variant={variant}
            aspect={aspect}
            slideClassName={slideClassName}
          />
        </div>
      </div>
    );
  }

  // Linear: full-width slide, no peek, no scale.
  return (
    <div
      role="group"
      aria-roledescription="slide"
      aria-label={slideAriaLabel}
      inert={!isActive}
      className={cn("min-w-0 flex-[0_0_100%]")}
      onClick={item.type === "image" ? imageDoubleTap : undefined}
    >
      <SlideRenderer
        item={item}
        ctx={{ isActive, index }}
        renderItem={renderItem}
        onDoubleTap={onDoubleTap}
        variant={variant}
        aspect={aspect}
        slideClassName={slideClassName}
      />
    </div>
  );
}

export function CarouselTrack({
  items,
  variant,
  peekRatio,
  aspect,
  loop,
  showIndicators,
  showNavButtons,
  rtl,
  renderItem,
  onSlideChange,
  onDoubleTap,
  labels,
  className,
  slideClassName,
  ref: forwardedRef,
}: CarouselTrackProps) {
  // Memoize Embla options — useEmblaCarousel re-initializes on options identity change.
  // Under loop, Embla force-disables containScroll; we don't set it explicitly there.
  // Under linear+no-loop, we trim duplicate edge snaps so prev/next stop cleanly.
  const emblaOptions = useMemo(
    () => ({
      align: variant === "gallery" ? ("center" as const) : ("start" as const),
      ...(variant === "linear" && !loop
        ? { containScroll: "trimSnaps" as const }
        : {}),
      loop,
      direction: rtl ? ("rtl" as const) : ("ltr" as const),
    }),
    [variant, loop, rtl],
  );

  const { ref, currentIndex, scrollTo, scrollPrev, scrollNext } =
    useEmblaWithState({ ...emblaOptions, onSelect: onSlideChange });

  // Stable ref-mirror for currentIndex — keeps imperative handle identity
  // stable across slide changes. Ref write inside passive useEffect.
  const currentIndexRef = useRef(currentIndex);
  useEffect(() => {
    currentIndexRef.current = currentIndex;
  });

  useImperativeHandle(
    forwardedRef,
    () => ({
      scrollTo,
      scrollPrev,
      scrollNext,
      getCurrentIndex: () => currentIndexRef.current,
    }),
    [scrollTo, scrollPrev, scrollNext],
  );

  // Gallery variant gets soft edge fades (mirrors kasder UX). Linear variant doesn't
  // — full-width slides have no peek to soften.
  const showEdgeGradients = variant === "gallery";

  // Keyboard nav — APG carousel pattern: ArrowLeft/Right scroll prev/next
  // (RTL-aware), Home/End jump to first/last. Wired on the focusable region
  // wrapper so users tabbing into the carousel get arrow-key control without
  // first focusing a child slide.
  const handleKeyDown = useCallback(
    (e: ReactKeyboardEvent<HTMLDivElement>) => {
      if (e.key === "ArrowLeft") {
        e.preventDefault();
        if (rtl) scrollNext();
        else scrollPrev();
      } else if (e.key === "ArrowRight") {
        e.preventDefault();
        if (rtl) scrollPrev();
        else scrollNext();
      } else if (e.key === "Home") {
        e.preventDefault();
        scrollTo(0);
      } else if (e.key === "End") {
        e.preventDefault();
        scrollTo(items.length - 1);
      }
    },
    [rtl, scrollPrev, scrollNext, scrollTo, items.length],
  );

  return (
    <div
      role="region"
      aria-roledescription="carousel"
      aria-label={labels.carouselLabel}
      tabIndex={0}
      onKeyDown={handleKeyDown}
      className={cn(
        "relative outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 rounded-md",
        className,
      )}
    >
      <div className="overflow-hidden" ref={ref}>
        <div className="flex">
          {items.map((item, index) => (
            <Slide
              key={item.id}
              item={item}
              index={index}
              total={items.length}
              isActive={index === currentIndex}
              isFirst={index === 0}
              isLast={index === items.length - 1}
              loop={loop}
              variant={variant}
              peekRatio={peekRatio}
              aspect={aspect}
              renderItem={renderItem}
              onDoubleTap={onDoubleTap}
              labels={labels}
              slideClassName={slideClassName}
            />
          ))}
        </div>
      </div>

      {showEdgeGradients ? (
        <>
          <div
            aria-hidden="true"
            className="pointer-events-none absolute inset-y-0 left-0 z-5 w-12 bg-linear-to-r from-background to-transparent"
          />
          <div
            aria-hidden="true"
            className="pointer-events-none absolute inset-y-0 right-0 z-5 w-12 bg-linear-to-l from-background to-transparent"
          />
        </>
      ) : null}

      {showNavButtons && (
        <NavButtons
          scrollPrev={scrollPrev}
          scrollNext={scrollNext}
          labels={labels}
        />
      )}

      {showIndicators && (
        <IndicatorDots
          total={items.length}
          currentIndex={currentIndex}
          scrollTo={scrollTo}
          labels={labels}
        />
      )}
    </div>
  );
}

"use client";

import type { ReactNode } from "react";
import { cn } from "@/lib/utils";
import { VideoPlayer01 } from "@/registry/components/media/video-player-01";
import type {
  LinearAspect,
  MediaCarousel01Variant,
  MediaItem,
  RenderItemContext,
} from "../types";

interface SlideRendererProps {
  item: MediaItem;
  ctx: RenderItemContext;
  renderItem?: (item: MediaItem, ctx: RenderItemContext) => ReactNode;
  onDoubleTap?: (item: MediaItem, index: number) => void;
  variant: MediaCarousel01Variant;
  aspect: LinearAspect;
  slideClassName?: string;
  /** True when this is the single-item shortcut. */
  isSingleItem?: boolean;
}

const ASPECT_CLASS: Record<LinearAspect, string> = {
  square: "aspect-square",
  video: "aspect-video",
  portrait: "aspect-[3/4]",
  auto: "",
};

/**
 * Renders a single slide. Three paths:
 *   1. `renderItem` provided → consumer takes over.
 *   2. `item.type === "image"` → built-in <img> handler.
 *   3. `item.type === "video"` → built-in <VideoPlayer01> handler with isActive propagation.
 *
 * The video handler is a deliberate cross-folder import — see Q-P1 in the plan
 * doc and the project memory note on the refined sealed-folder rule.
 */
export function SlideRenderer({
  item,
  ctx,
  renderItem,
  onDoubleTap,
  variant,
  aspect,
  slideClassName,
  isSingleItem = false,
}: SlideRendererProps) {
  // Aspect ratio: gallery + single-item are always square; linear uses prop.
  const aspectClass =
    variant === "gallery" || isSingleItem
      ? "aspect-square"
      : ASPECT_CLASS[aspect];

  if (renderItem) {
    return (
      <div className={cn(aspectClass, "overflow-hidden", slideClassName)}>
        {renderItem(item, ctx)}
      </div>
    );
  }

  if (item.type === "image") {
    return (
      <div className={cn(aspectClass, "overflow-hidden", slideClassName)}>
        <img
          src={item.url}
          alt={item.alt ?? ""}
          loading="lazy"
          className="h-full w-full object-cover"
        />
      </div>
    );
  }

  return (
    <div className={cn(aspectClass, "overflow-hidden", slideClassName)}>
      <VideoPlayer01
        src={item.url}
        poster={item.poster}
        isActive={ctx.isActive}
        onDoubleTap={
          onDoubleTap ? () => onDoubleTap(item, ctx.index) : undefined
        }
      />
    </div>
  );
}

"use client";

import { ChevronLeft, ChevronRight } from "lucide-react";
import { Button } from "@/components/ui/button";

interface NavButtonsProps {
  scrollPrev: () => void;
  scrollNext: () => void;
  labels: { previousSlide: string; nextSlide: string };
}

export function NavButtons({ scrollPrev, scrollNext, labels }: NavButtonsProps) {
  return (
    <>
      <Button
        type="button"
        variant="secondary"
        size="icon"
        className="absolute top-1/2 left-2 z-10 h-8 w-8 -translate-y-1/2 rounded-full opacity-80 hover:opacity-100 rtl:rotate-180"
        onClick={scrollPrev}
        aria-label={labels.previousSlide}
      >
        <ChevronLeft className="h-4 w-4" aria-hidden="true" />
      </Button>
      <Button
        type="button"
        variant="secondary"
        size="icon"
        className="absolute top-1/2 right-2 z-10 h-8 w-8 -translate-y-1/2 rounded-full opacity-80 hover:opacity-100 rtl:rotate-180"
        onClick={scrollNext}
        aria-label={labels.nextSlide}
      >
        <ChevronRight className="h-4 w-4" aria-hidden="true" />
      </Button>
    </>
  );
}

"use client";

import { cn } from "@/lib/utils";

interface IndicatorDotsProps {
  total: number;
  currentIndex: number;
  scrollTo: (index: number) => void;
  labels: { goToSlide: string };
}

export function IndicatorDots({
  total,
  currentIndex,
  scrollTo,
  labels,
}: IndicatorDotsProps) {
  return (
    <div className="absolute bottom-3 left-1/2 z-10 flex -translate-x-1/2 gap-1.5">
      {Array.from({ length: total }, (_, i) => {
        const isActive = i === currentIndex;
        return (
          <button
            key={i}
            type="button"
            onClick={() => scrollTo(i)}
            aria-label={`${labels.goToSlide} ${i + 1}`}
            aria-current={isActive ? "true" : undefined}
            className={cn(
              "h-1.5 rounded-full transition-all duration-300 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
              isActive
                ? "w-4 bg-primary"
                : "w-1.5 bg-primary/40 hover:bg-primary/60",
            )}
          />
        );
      })}
    </div>
  );
}

"use client";

import { useCallback, useEffect, useRef, useSyncExternalStore } from "react";
import useEmblaCarousel from "embla-carousel-react";
import type {
  EmblaCarouselType,
  EmblaOptionsType,
} from "embla-carousel";

export interface UseEmblaWithStateOptions extends EmblaOptionsType {
  /** Fires on slide change. Does NOT fire on initial mount-sync. */
  onSelect?: (index: number) => void;
}

export interface UseEmblaWithStateResult {
  ref: (node: HTMLElement | null) => void;
  api: EmblaCarouselType | null;
  currentIndex: number;
  scrollTo: (index: number) => void;
  scrollPrev: () => void;
  scrollNext: () => void;
}

const SERVER_INDEX = 0;

/**
 * Wraps `useEmblaCarousel` with currentIndex state via `useSyncExternalStore`
 * (avoids `setState`-in-effect lint violations) and lifecycle callbacks.
 *
 * **Mount-sync semantics:** `currentIndex` syncs to Embla's initial snap
 * automatically on mount. The user's `onSelect` callback does NOT fire on
 * the mount-sync — only on real slide changes (tracked via `isFirstFireRef`).
 *
 * Embla options should be memoized by the caller (Embla re-initializes on
 * options-object identity change).
 */
export function useEmblaWithState({
  onSelect,
  ...emblaOptions
}: UseEmblaWithStateOptions): UseEmblaWithStateResult {
  const [emblaRef, emblaApi] = useEmblaCarousel(emblaOptions);

  // External-store subscription for currentIndex — no setState in effect.
  const subscribe = useCallback(
    (callback: () => void) => {
      if (!emblaApi) return () => {};
      emblaApi.on("select", callback);
      return () => {
        emblaApi.off("select", callback);
      };
    },
    [emblaApi],
  );

  const getSnapshot = useCallback(
    () => emblaApi?.selectedScrollSnap() ?? SERVER_INDEX,
    [emblaApi],
  );

  const getServerSnapshot = useCallback(() => SERVER_INDEX, []);

  const currentIndex = useSyncExternalStore(
    subscribe,
    getSnapshot,
    getServerSnapshot,
  );

  // Stable ref for onSelect callback — avoids effect cascade on identity change.
  const onSelectRef = useRef(onSelect);
  useEffect(() => {
    onSelectRef.current = onSelect;
  });

  // Fire user `onSelect` only on real slide changes — skip the initial mount.
  const isFirstFireRef = useRef(true);
  useEffect(() => {
    if (isFirstFireRef.current) {
      isFirstFireRef.current = false;
      return;
    }
    onSelectRef.current?.(currentIndex);
  }, [currentIndex]);

  const scrollTo = useCallback(
    (index: number) => {
      emblaApi?.scrollTo(index);
    },
    [emblaApi],
  );
  const scrollPrev = useCallback(() => {
    emblaApi?.scrollPrev();
  }, [emblaApi]);
  const scrollNext = useCallback(() => {
    emblaApi?.scrollNext();
  }, [emblaApi]);

  return {
    ref: emblaRef,
    api: emblaApi ?? null,
    currentIndex,
    scrollTo,
    scrollPrev,
    scrollNext,
  };
}
